$("signupForm").onsubmit=async e=>{e.preventDefault();const form=e.currentTarget,button=$("signupSubmit"),messageBox=$("signupMessage");let credential=null,profileCreated=false;button.disabled=true;button.textContent="Envoi…";messageBox.textContent="";registrationInProgress=true;try{credential=await createUserWithEmailAndPassword(auth,$("signupEmail").value.trim(),$("signupPassword").value);await setDoc(doc(db,"users",credential.user.uid),{firstName:$("signupFirstName").value.trim(),lastName:$("signupLastName").value.trim(),floor:$("signupFloor").value.trim(),apartment:$("signupApartment").value.trim(),mobile:$("signupMobile").value.trim(),email:credential.user.email,role:"pending",createdAt:serverTimestamp()});profileCreated=true;await signOut(auth).catch(error=>console.warn("Déconnexion après inscription",error));form.reset();messageBox.className="success-message";messageBox.textContent="Votre compte a bien été créé et soumis à la validation de l’AGP. Vous pourrez vous connecter dès que votre accès aura été activé.";}catch(error){if(credential&&!profileCreated)await deleteUser(credential.user).catch(cleanupError=>console.warn("Nettoyage du compte incomplet",cleanupError));console.error(error);messageBox.className="error";messageBox.textContent=error.code==="auth/email-already-in-use"?"Un compte existe déjà avec cette adresse. Utilisez « Mot de passe oublié » depuis la connexion si nécessaire.":error.code==="auth/weak-password"?"Choisissez un mot de passe d’au moins 8 caractères.":error.code==="auth/invalid-email"?"Vérifiez l’adresse e-mail saisie.":"Impossible d’enregistrer la demande pour le moment. Réessayez dans quelques instants.";}finally{registrationInProgress=false;button.disabled=false;button.textContent="Envoyer ma demande";}};
