onAuthStateChanged(auth, async user=>{
  if(registrationInProgress)return;
  currentUser=user; currentRole=null;
  $("requestAccess").hidden=!!user; $("homeSignup").hidden=!!user;
  if(!user){$("authButton").textContent="Se connecter";$("statusText").textContent="Association du Grand Pavois";return;}
  $("authButton").textContent="Mon espace";$("statusText").textContent=user.email;
  try{const snap=await getDoc(doc(db,"users",user.uid));if(!snap.exists())throw new Error("denied");const profile=snap.data();if(!["member","admin"].includes(profile.role)){const accessMessage=profile.role==="refused"?`Votre demande de compte a été refusée.${profile.rejectionComment?` Motif : ${profile.rejectionComment}`:""}`:profile.role==="disabled"?"Votre accès à l’application est suspendu.":"Votre compte est en attente de validation par l’AGP.";await signOut(auth);$("loginError").textContent=accessMessage;openLogin();return;}currentRole=profile.role;$("memberTitle").textContent=`Bienvenue${profile.firstName?` ${profile.firstName}`:""}`;if(currentRole==="admin"){route("admin");selectAdmin("activities");}else{route("member");loadDashboard();}}
  catch{await signOut(auth);$("loginError").textContent="Impossible de vérifier votre accès pour le moment.";openLogin();}
});

async function getItems(section, includeHidden=false){let ref=collection(db,config[section].collection),snap;if(!includeHidden&&["classifieds","aid"].includes(section)){const [published,own]=await Promise.all([getDocs(query(ref,where("status","==","published"))),getDocs(query(ref,where("authorUid","==",currentUser.uid)))]),merged=new Map();[...published.docs,...own.docs].forEach(d=>merged.set(d.id,{id:d.id,...d.data()}));return [...merged.values()];}try{snap=section==="activities"?await getDocs(query(ref,orderBy("eventDate","asc"))):await getDocs(ref);}catch{snap=await getDocs(ref);}return snap.docs.map(d=>({id:d.id,...d.data()})).filter(x=>includeHidden||section==="activities"?includeHidden||x.published!==false:true);}
function upcoming(x){const d=asDate(x.eventDate);if(Number.isNaN(d.getTime()))return true;d.setHours(23,59,59,999);return d>=new Date();}
function activityCard(x,joined=false,variant=""){const external=x.eventType==="external",past=!upcoming(x),closed=past||(x.registrationOpen===false&&!joined),label=external?"Événement extérieur":(x.category||"Activité AGP");return `<article class="member-activity-card ${variant} ${past?"past-activity":""} ${external?"external-event":""}"><div class="activity-date"><span>${escapeHtml(new Intl.DateTimeFormat("fr-FR",{month:"short"}).format(asDate(x.eventDate)).toUpperCase())}</span><b>${escapeHtml(new Intl.DateTimeFormat("fr-FR",{day:"2-digit"}).format(asDate(x.eventDate)))}</b></div><div class="activity-body"><span class="pill">${escapeHtml(label)}</span><h3>${escapeHtml(x.title)}</h3><p class="activity-meta">${escapeHtml([formatDate(x.eventDate),x.time,x.location].filter(Boolean).join(" · "))}</p>${!external&&x.capacity?`<p class="activity-capacity">👥 ${escapeHtml(x.capacity)} places maximum</p>`:""}${external?`<p class="external-event-notice">Information communiquée par l’AGP — cet événement n’est pas organisé par l’association.</p>`:""}<p class="activity-description">${escapeHtml(x.description)}</p>${external&&x.externalUrl?`<a class="external-event-link" href="${escapeHtml(safeUrl(x.externalUrl))}" target="_blank" rel="noopener noreferrer">Informations de l’organisateur ↗</a>`:""}${variant?`<button class="activity-details-button" data-open-activity>Voir ${external?"l’événement":"l’activité"}</button>`:""}${external?`<span class="information-only-badge">Aucune inscription dans l’application</span>`:`<button class="registration-button ${joined&&!past?"joined":""}" data-join-activity="${x.id}" ${closed?"disabled":""}>${past?"Activité passée":joined?"✓ Je participe — annuler":closed?"Inscriptions closes":"Je participe"}</button>`}</div></article>`;}
function contentCard(section,x){if(section==="artisans"){const phone=String(x.phone||"").replace(/[^+\d]/g,"");return `<article class="result artisan-card"><span class="pill">${escapeHtml(x.category||"Artisan")}</span><h3>${escapeHtml(x.name)}</h3><p>${escapeHtml(x.description||"")}</p>${x.phone?`<a class="artisan-phone" href="tel:${escapeHtml(phone)}">☎ ${escapeHtml(x.phone)}</a>`:""}</article>`;}if(["classifieds","aid"].includes(section)){const contact=String(x.contact||"").trim(),isEmail=contact.includes("@"),href=isEmail?`mailto:${contact}`:`tel:${contact.replace(/[^+\d]/g,"")}`,progress=x.progress||"open",progressLabels={open:"Ouverte",in_progress:"En cours",resolved:"Résolue"},own=x.authorUid===currentUser?.uid,statusLabels={pending:"En attente de validation",refused:"Refusée"},images=Array.isArray(x.images)?x.images.filter(value=>String(value).startsWith("data:image/")):[],created=asDate(x.createdAt),publication=!Number.isNaN(created.getTime())?`Publié le ${formatDate(x.createdAt)} · `:"";return `<article class="result classified-card">${section==="classifieds"&&images.length?`<div class="classified-gallery">${images.map((src,index)=>`<a href="${src}" target="_blank" rel="noopener noreferrer"><img src="${src}" alt="${escapeHtml(x.title)} — photo ${index+1}" loading="lazy"></a>`).join("")}</div>`:""}<div class="card-pills"><span class="pill">${escapeHtml(x.category||(section==="aid"?"Entraide":"Annonce"))}</span>${section==="aid"?`<span class="progress-pill ${escapeHtml(progress)}">${progressLabels[progress]||"Ouverte"}</span>`:""}${x.status!=="published"?`<span class="submission-status ${escapeHtml(x.status)}">${statusLabels[x.status]||escapeHtml(x.status)}</span>`:""}</div><h3>${escapeHtml(x.title)}</h3><p>${escapeHtml(x.description||"")}</p><small>${escapeHtml(publication)}Proposé par ${escapeHtml(x.authorName||"un adhérent")}</small>${contact?`<a class="artisan-phone" href="${escapeHtml(href)}">${isEmail?"✉":"☎"} ${escapeHtml(contact)}</a>`:""}${own?`<div class="member-owner-actions"><button data-member-edit="${x.id}" data-section="${section}">Modifier</button>${section==="aid"&&x.status==="published"&&progress!=="resolved"?`<button data-member-progress="${x.id}" data-next-progress="${progress==="open"?"in_progress":"resolved"}" data-section="${section}">${progress==="open"?"Indiquer en cours":"Marquer résolue"}</button>`:""}<button class="danger" data-member-delete="${x.id}" data-section="${section}">${section==="classifieds"&&x.status==="published"?"Annonce terminée":"Retirer"}</button></div>`:""}</article>`;}const meta=[x.category,x.authorName];return `<article class="result"><span class="pill">${escapeHtml(x.category||config[section].title)}</span><h3>${escapeHtml(x.title||x.name)}</h3><p>${escapeHtml(x.description||"")}</p><small>${escapeHtml(meta.filter(Boolean).join(" · "))}</small></article>`;}
async function getMyRegistrations(){const snap=await getDocs(query(collection(db,"activityRegistrations"),where("userUid","==",currentUser.uid)));return new Set(snap.docs.map(d=>d.data().activityId));}
function backupValue(value){if(value?.toDate instanceof Function)return value.toDate().toISOString();if(Array.isArray(value))return value.map(backupValue);if(value&&typeof value==="object")return Object.fromEntries(Object.entries(value).map(([key,item])=>[key,backupValue(item)]));return value;}
async function backupApplicationData(){if(currentRole!=="admin")return;const collections=["users","publicActivities","activityRegistrations","classifieds","aid","artisans","magazines","magazinePages","photoAlbums","albumPhotos"],button=$("backupData");button.disabled=true;button.textContent="Préparation de la sauvegarde…";try{const snapshots=await Promise.all(collections.map(name=>getDocs(collection(db,name)))),data={format:"AGP-et-Vous-backup",version:1,exportedAt:new Date().toISOString(),containsPersonalData:true,collections:{}};collections.forEach((name,index)=>{data.collections[name]=snapshots[index].docs.map(item=>({id:item.id,...backupValue(item.data())}));});const json=JSON.stringify(data,null,2),blob=new Blob([json],{type:"application/json;charset=utf-8"}),link=document.createElement("a"),date=new Date().toISOString().slice(0,10);link.href=URL.createObjectURL(blob);link.download=`sauvegarde-agp-${date}.json`;link.click();setTimeout(()=>URL.revokeObjectURL(link.href),1000);message("Sauvegarde téléchargée. Conservez ce fichier dans un emplacement privé.");}catch(error){console.error(error);message("La sauvegarde n’a pas pu être créée.","error");}finally{button.disabled=false;button.textContent="⇩ Sauvegarder les données";}}
async function getMediaImages(collectionName,parentId){const snap=await getDocs(query(collection(db,collectionName),where("parentId","==",parentId)));return snap.docs.map(d=>({id:d.id,...d.data()})).sort((a,b)=>(a.order||0)-(b.order||0));}
async function renderMagazineLibrary(out,items){const magazines=[...items].sort((a,b)=>asDate(b.issueDate)-asDate(a.issueDate)),pages=await Promise.all(magazines.map(item=>getMediaImages("magazinePages",item.id)));out.innerHTML+=`<div class="magazine-library">${magazines.length?magazines.map((item,index)=>{const issuePages=pages[index];return `<article class="magazine-card">${issuePages[0]?`<img src="${issuePages[0].imageData}" alt="Couverture ${escapeHtml(item.title)}" loading="lazy">`:'<div class="magazine-placeholder">AGP<br>MAG</div>'}<div><span class="pill">AGP MAG</span><h3>${escapeHtml(item.title)}</h3><p>${escapeHtml(formatDate(item.issueDate))}</p><small>${escapeHtml(item.description||"")}</small><b class="media-count">${issuePages.length} page${issuePages.length>1?"s":""}</b></div>${issuePages.length?`<details class="magazine-reader"><summary>Lire le magazine</summary><div>${issuePages.map((page,pageIndex)=>`<figure><img src="${page.imageData}" alt="${escapeHtml(item.title)} — page ${pageIndex+1}" loading="lazy"><figcaption>Page ${pageIndex+1} sur ${issuePages.length}</figcaption></figure>`).join("")}</div></details>`:""}</article>`;}).join(""):"<div class='notice dashboard-empty'><b>Aucun AGP Mag n’est encore disponible.</b><span>Les prochains numéros apparaîtront ici.</span></div>"}</div>`;}
async function renderPhotoAlbums(out,items){const albums=[...items].sort((a,b)=>asDate(b.eventDate)-asDate(a.eventDate)),photos=await Promise.all(albums.map(item=>getMediaImages("albumPhotos",item.id)));out.innerHTML+=`<div class="album-library">${albums.length?albums.map((item,index)=>{const albumPhotos=photos[index];return `<article class="album-card">${albumPhotos[0]?`<img class="album-cover" src="${albumPhotos[0].imageData}" alt="${escapeHtml(item.title)}" loading="lazy">`:'<div class="album-placeholder">📷</div>'}<div class="album-copy"><span class="pill">ALBUM PHOTO</span><h3>${escapeHtml(item.title)}</h3><p>${escapeHtml(formatDate(item.eventDate))}</p><small>${escapeHtml(item.description||"")}</small><b class="media-count">${albumPhotos.length} photo${albumPhotos.length>1?"s":""}</b></div>${albumPhotos.length?`<div class="photo-grid">${albumPhotos.map((photo,photoIndex)=>`<a href="${photo.imageData}" target="_blank" rel="noopener noreferrer"><img src="${photo.imageData}" alt="${escapeHtml(item.title)} — photo ${photoIndex+1}" loading="lazy"></a>`).join("")}</div>`:""}</article>`;}).join(""):"<div class='notice dashboard-empty'><b>Aucun album photo n’est encore disponible.</b><span>Les souvenirs des prochains événements apparaîtront ici.</span></div>"}</div>`;}
async function loadDashboard(){currentMemberSection=null;document.querySelector('[data-view="member"]').classList.remove("member-browsing");memberBackButton.hidden=true;const box=$("memberUpcomingActivities");box.innerHTML="<div class='notice dashboard-empty'>Chargement des prochains rendez-vous…</div>";$("privateResults").innerHTML="";const [acts,aid,ads,arts,joined]=await Promise.all([getItems("activities").catch(()=>[]),getItems("aid").catch(()=>[]),getItems("classifieds").catch(()=>[]),getItems("artisans").catch(()=>[]),getMyRegistrations().catch(()=>new Set())]);const next=acts.filter(upcoming).slice(0,3);box.innerHTML=next.length?next.map((x,index)=>activityCard(x,joined.has(x.id),index===0?"featured":"secondary-activity")).join(""):"<div class='notice dashboard-empty'><b>Le prochain rendez-vous sera bientôt annoncé.</b><span>Revenez consulter cette page dans quelques jours.</span></div>";$("aidCount").textContent=aid.filter(x=>x.status==="published").length;$("classifiedsCount").textContent=ads.filter(x=>x.status==="published").length;$("artisansCount").textContent=arts.length;}
async function loadMemberSection(section){currentMemberSection=section;document.querySelector('[data-view="member"]').classList.add("member-browsing");memberBackButton.hidden=false;const out=$("privateResults");out.innerHTML="<div class='notice'>Chargement…</div>";try{const [items,joined]=await Promise.all([getItems(section),section==="activities"?getMyRegistrations():Promise.resolve(new Set())]);const add=["classifieds","aid"].includes(section)?`<button class="primary member-add" data-member-add="${section}">＋ Proposer ${section==="aid"?"une demande":"une annonce"}</button>`:"";out.innerHTML=`<div class="section-title"><div><span>ESPACE PRIVÉ</span><h2>${config[section].title}</h2></div>${add}</div>`;if(section==="artisans")return renderArtisanDirectory(out,items);if(section==="classifieds")return renderClassifiedsDirectory(out,items);if(section==="aid")return renderAidDirectory(out,items);if(section==="magazines")return renderMagazineLibrary(out,items);if(section==="photoAlbums")return renderPhotoAlbums(out,items);if(section==="activities"){const future=items.filter(upcoming),past=items.filter(item=>!upcoming(item)).sort((a,b)=>asDate(b.eventDate)-asDate(a.eventDate));out.innerHTML+=future.length?future.map(x=>activityCard(x,joined.has(x.id))).join(""):"<div class='notice'>Aucune activité à venir pour le moment.</div>";if(past.length)out.innerHTML+=`<details class="activity-history"><summary>Voir les activités passées (${past.length})</summary><div>${past.map(x=>activityCard(x,joined.has(x.id))).join("")}</div></details>`;return;}out.innerHTML+=items.length?items.map(x=>contentCard(section,x)).join(""):"<div class='notice'>Aucun contenu publié pour le moment.</div>";}catch(error){console.error(error);out.innerHTML="<div class='notice'>Impossible de charger cette rubrique.</div>";}}

function renderArtisanDirectory(out,items){
  const artisans=[...items].sort((a,b)=>String(a.category||"").localeCompare(String(b.category||""),"fr")||String(a.name||"").localeCompare(String(b.name||""),"fr"));
  const categories=[...new Set(artisans.map(x=>x.category).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"fr"));
  out.innerHTML+=`<div class="artisan-tools"><label><span>Rechercher</span><input id="artisanSearch" type="search" placeholder="Nom, métier, service…" autocomplete="off"></label><label><span>Catégorie</span><select id="artisanCategory"><option value="">Toutes les catégories</option>${categories.map(value=>`<option value="${escapeHtml(value)}">${escapeHtml(value)}</option>`).join("")}</select></label><div id="artisanResultCount" class="artisan-result-count"></div></div><div id="artisanDirectory" class="artisan-directory"></div>`;
  const normalize=value=>String(value||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
  const draw=()=>{const term=normalize($("artisanSearch").value.trim()),category=$("artisanCategory").value;const filtered=artisans.filter(x=>(!category||x.category===category)&&(!term||normalize([x.name,x.category,x.description,x.phone].join(" ")).includes(term)));$("artisanResultCount").textContent=`${filtered.length} contact${filtered.length>1?"s":""}`;$("artisanDirectory").innerHTML=filtered.length?filtered.map(x=>contentCard("artisans",x)).join(""):"<div class='notice'>Aucun contact ne correspond à cette recherche.</div>";};
  $("artisanSearch").oninput=draw;$("artisanCategory").onchange=draw;draw();
}

function renderClassifiedsDirectory(out,items){
  const ads=[...items].sort((a,b)=>asDate(b.createdAt)-asDate(a.createdAt));
  const categories=["Vente","Don","Recherche","Prêt"];
  out.innerHTML+=`<div class="artisan-tools"><label><span>Rechercher</span><input id="classifiedSearch" type="search" placeholder="Objet, description, adhérent…" autocomplete="off"></label><label><span>Catégorie</span><select id="classifiedCategory"><option value="">Toutes les catégories</option>${categories.map(value=>`<option value="${value}">${value}</option>`).join("")}</select></label><div id="classifiedResultCount" class="artisan-result-count"></div></div><div id="classifiedDirectory" class="artisan-directory"></div>`;
  const normalize=value=>String(value||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
  const draw=()=>{const term=normalize($("classifiedSearch").value.trim()),category=$("classifiedCategory").value;const filtered=ads.filter(x=>(!category||x.category===category)&&(!term||normalize([x.title,x.description,x.authorName].join(" ")).includes(term)));$("classifiedResultCount").textContent=`${filtered.length} annonce${filtered.length>1?"s":""}`;$("classifiedDirectory").innerHTML=filtered.length?filtered.map(x=>contentCard("classifieds",x)).join(""):"<div class='notice'>Aucune annonce ne correspond à cette recherche.</div>";};
  $("classifiedSearch").oninput=draw;$("classifiedCategory").onchange=draw;draw();
}

function renderAidDirectory(out,items){
  const requests=[...items].sort((a,b)=>asDate(b.createdAt)-asDate(a.createdAt));
  out.innerHTML+=`<div class="artisan-tools"><label><span>Rechercher</span><input id="aidSearch" type="search" placeholder="Besoin, service, adhérent…" autocomplete="off"></label><label><span>État</span><select id="aidProgress"><option value="">Tous les états</option><option value="open">Ouverte</option><option value="in_progress">En cours</option><option value="resolved">Résolue</option></select></label><div id="aidResultCount" class="artisan-result-count"></div></div><div id="aidDirectory" class="artisan-directory"></div>`;
  const normalize=value=>String(value||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
  const draw=()=>{const term=normalize($("aidSearch").value.trim()),progress=$("aidProgress").value;const filtered=requests.filter(x=>(!progress||(x.progress||"open")===progress)&&(!term||normalize([x.title,x.description,x.authorName,x.category].join(" ")).includes(term)));$("aidResultCount").textContent=`${filtered.length} demande${filtered.length>1?"s":""}`;$("aidDirectory").innerHTML=filtered.length?filtered.map(x=>contentCard("aid",x)).join(""):"<div class='notice'>Aucune demande ne correspond à cette recherche.</div>";};
  $("aidSearch").oninput=draw;$("aidProgress").onchange=draw;draw();
}
async function handleActivityRegistration(e){const button=e.target.closest("[data-join-activity]");if(!button)return;button.disabled=true;const activityId=button.dataset.joinActivity,registrationId=`${activityId}_${currentUser.uid}`;try{if(button.classList.contains("joined"))await deleteDoc(doc(db,"activityRegistrations",registrationId));else await setDoc(doc(db,"activityRegistrations",registrationId),{activityId,userUid:currentUser.uid,userName:$("memberTitle").textContent.replace(/^Bienvenue\s*/,"")||currentUser.email,userEmail:currentUser.email,createdAt:serverTimestamp()});if(currentMemberSection==="activities")await loadMemberSection("activities");else await loadDashboard();}catch(error){console.error(error);button.disabled=false;}}
async function handleMemberAction(e){if(e.target.closest("[data-join-activity]"))return handleActivityRegistration(e);const edit=e.target.closest("[data-member-edit]"),remove=e.target.closest("[data-member-delete]"),progress=e.target.closest("[data-member-progress]"),add=e.target.closest("[data-member-add]");try{if(edit){const section=edit.dataset.section,snap=await getDoc(doc(db,config[section].collection,edit.dataset.memberEdit));return openMemberProposal(section,edit.dataset.memberEdit,snap.data());}if(remove){if(remove.dataset.confirm!=="true"){remove.dataset.confirm="true";remove.textContent=remove.dataset.section==="classifieds"?"Confirmer la clôture":"Confirmer le retrait";return;}await deleteDoc(doc(db,config[remove.dataset.section].collection,remove.dataset.memberDelete));return loadMemberSection(remove.dataset.section);}if(progress){await updateDoc(doc(db,config[progress.dataset.section].collection,progress.dataset.memberProgress),{progress:progress.dataset.nextProgress,updatedAt:serverTimestamp()});return loadMemberSection(progress.dataset.section);}if(add)return openMemberProposal(add.dataset.memberAdd);}catch(error){console.error(error);$("privateResults").insertAdjacentHTML("afterbegin","<div class='notice'>L’opération a échoué.</div>");}}

function openMemberProposal(section,id=null,data={}){$("privateResults").innerHTML=`<section class="admin-panel"><div class="panel-heading"><div><span>${id?"MODIFICATION":"PROPOSITION"}</span><h2>${id?"Modifier":section==="aid"?"Nouvelle demande d’entraide":"Nouvelle annonce"}</h2></div></div><form id="memberProposal" class="content-form"><label>Titre<input name="title" maxlength="100" required value="${escapeHtml(data.title)}"></label><label>Catégorie<select name="category">${(section==="aid"?["Demande","Proposition"]:["Vente","Don","Recherche","Prêt"]).map(v=>`<option ${data.category===v?"selected":""}>${v}</option>`).join("")}</select></label><label>Description<textarea name="description" rows="10" maxlength="2500" required>${escapeHtml(data.description)}</textarea></label>${section==="classifieds"?`<label>Photos de l’annonce<input name="images" type="file" accept="image/jpeg,image/png" multiple><small>Jusqu’à 3 photos. Elles seront automatiquement adaptées pour le téléphone.</small></label>`:""}<label>Votre nom<input name="authorName" maxlength="80" required value="${escapeHtml(data.authorName)}"></label><label>Téléphone ou e-mail de contact<input name="contact" maxlength="100" required placeholder="06… ou nom@exemple.fr" value="${escapeHtml(data.contact)}"></label><div class="form-actions"><button type="button" class="secondary-action" data-member-section="${section}">Annuler</button><button class="primary">${id?"Enregistrer et soumettre":"Envoyer pour validation"}</button></div></form></section>`;$("memberProposal").onsubmit=async event=>{event.preventDefault();const form=event.currentTarget,f=new FormData(form),files=section==="classifieds"?f.getAll("images").filter(file=>file?.size):[];if(files.length>3){form.insertAdjacentHTML("afterbegin","<div class='notice'>Sélectionnez au maximum 3 photos.</div>");return;}const button=form.querySelector('button[type="submit"],button.primary'),payload={title:f.get("title").trim(),category:f.get("category"),description:f.get("description").trim(),authorName:f.get("authorName").trim(),contact:String(f.get("contact")||"").trim(),progress:section==="aid"?(data.progress||"open"):null,authorUid:currentUser.uid,status:"pending",updatedAt:serverTimestamp()};button.disabled=true;button.textContent="Préparation…";try{if(files.length){payload.images=[];for(let index=0;index<files.length;index++){button.textContent=`Photo ${index+1} sur ${files.length}…`;payload.images.push(await compressMediaImage(files[index],1000,220000));}}else if(id&&Array.isArray(data.images))payload.images=data.images;if(id)await updateDoc(doc(db,config[section].collection,id),payload);else{payload.createdAt=serverTimestamp();await addDoc(collection(db,config[section].collection),payload);}$("privateResults").innerHTML="<div class='notice success'>Votre proposition a été transmise à l’administration.</div>";}catch(error){console.error(error);button.disabled=false;button.textContent=id?"Enregistrer et soumettre":"Envoyer pour validation";form.insertAdjacentHTML("afterbegin","<div class='notice'>L’envoi a échoué.</div>");}};}

