async function importExcelArtisans(){
  const button=importArtisansButton;button.disabled=true;button.textContent="Import en cours…";
  try{
    await Promise.all(excelArtisans.map(([row,category,name,phone,description])=>setDoc(doc(db,"artisans",`excel-${row}`),{category,name,phone,description,status:"published",source:"LISTE DES ARTISANS.xlsx",sourceRow:row,updatedAt:serverTimestamp()},{merge:true})));
    message(`${excelArtisans.length} contacts importés avec succès.`);button.textContent="Liste Excel importée";await loadAdminList();
  }catch(error){console.error(error);message("L’import a échoué.","error");button.disabled=false;button.textContent="Réessayer l’import Excel";}
}

async function selectAdmin(section){adminSection=section;editingId=null;closeEditor();$("adminSectionTitle").textContent=config[section].title;$("newItem").hidden=["classifieds","aid","users"].includes(section);importArtisansButton.hidden=section!=="artisans";document.querySelectorAll("[data-admin-section]").forEach(b=>b.classList.toggle("active-feature",b.dataset.adminSection===section));await Promise.all([loadAdminList(),updateAdminBadges()]);}

async function updateAdminBadges(){document.querySelectorAll("#adminMenu .admin-pending-badge,#adminMenu .section-total-badge").forEach(badge=>badge.remove());}
async function loadAdminList(){const out=$("adminList");out.innerHTML="<div class='admin-empty'>Chargement…</div>";try{const items=await getItems(adminSection,true);if(adminSection==="users")return renderUserAdmin(out,items);if(adminSection==="artisans")return renderArtisanAdmin(out,items);if(!items.length)return out.innerHTML="<div class='admin-empty'>Aucun élément.</div>";out.innerHTML=items.map(x=>adminRow(x)).join("");}catch(e){console.error(e);out.innerHTML="<div class='admin-empty error-text'>Impossible de charger cette rubrique.</div>";}}

function renderArtisanAdmin(out,items){
  const artisans=[...items].sort((a,b)=>String(a.category||"").localeCompare(String(b.category||""),"fr")||String(a.name||"").localeCompare(String(b.name||""),"fr")),categories=[...new Set(artisans.map(item=>item.category).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"fr")),normalize=value=>String(value||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
  out.innerHTML=`<div class="artisan-tools admin-artisan-tools"><label><span>Rechercher</span><input id="adminArtisanSearch" type="search" placeholder="Nom, métier, téléphone…" autocomplete="off"></label><label><span>Métier</span><select id="adminArtisanCategory"><option value="">Tous les métiers</option>${categories.map(category=>`<option value="${escapeHtml(category)}">${escapeHtml(category)}</option>`).join("")}</select></label><button id="exportArtisans" class="export-users" type="button">⇩ Exporter vers Excel</button><div id="adminArtisanCount" class="artisan-result-count"></div></div><div id="adminArtisanDirectory" class="admin-list-inner"></div>`;
  let filtered=artisans;
  const draw=()=>{const term=normalize($("adminArtisanSearch").value.trim()),category=$("adminArtisanCategory").value;filtered=artisans.filter(item=>(!category||item.category===category)&&(!term||normalize([item.name,item.category,item.phone,item.description].join(" ")).includes(term)));$("adminArtisanCount").textContent=`${filtered.length} contact${filtered.length>1?"s":""} affiché${filtered.length>1?"s":""}`;$("adminArtisanDirectory").innerHTML=filtered.length?filtered.map(item=>adminRow(item)).join(""):"<div class='admin-empty'>Aucun artisan ne correspond à cette recherche.</div>";};
  $("adminArtisanSearch").oninput=draw;$("adminArtisanCategory").onchange=draw;$("exportArtisans").onclick=()=>exportArtisansCsv(filtered);draw();
}
