async function compressMediaImage(file,maxEdge=1400,maxLength=820000){if(!file.type.startsWith("image/"))throw new Error("format");const objectUrl=URL.createObjectURL(file),image=new Image();try{await new Promise((resolve,reject)=>{image.onload=resolve;image.onerror=reject;image.src=objectUrl;});const scale=Math.min(1,maxEdge/Math.max(image.naturalWidth,image.naturalHeight)),canvas=document.createElement("canvas");canvas.width=Math.max(1,Math.round(image.naturalWidth*scale));canvas.height=Math.max(1,Math.round(image.naturalHeight*scale));const context=canvas.getContext("2d");context.fillStyle="#fff";context.fillRect(0,0,canvas.width,canvas.height);context.drawImage(image,0,0,canvas.width,canvas.height);let quality=.8,data=canvas.toDataURL("image/jpeg",quality);while(data.length>maxLength&&quality>.3){quality-=.07;data=canvas.toDataURL("image/jpeg",quality);}if(data.length>maxLength*1.12)throw new Error("image-too-large");return data;}finally{URL.revokeObjectURL(objectUrl);}}
async function saveAdminMediaItem(e){e.preventDefault();const form=e.currentTarget,f=new FormData(form),files=f.getAll("images").filter(file=>file?.size),section=adminSection,pageCollection=section==="magazines"?"magazinePages":"albumPhotos",dateField=section==="magazines"?"issueDate":"eventDate",button=$("saveItem");if(files.length>30)return message("Sélectionnez au maximum 30 images à la fois.","error");if(!editingId&&!files.length)return message("Sélectionnez au moins une image.","error");button.disabled=true;button.textContent="Préparation des images…";try{const payload={title:f.get("title").trim(),description:f.get("description").trim(),[dateField]:Timestamp.fromDate(new Date(`${f.get("date")}T12:00:00`)),status:"published",updatedAt:serverTimestamp()};let parentId=editingId;if(parentId)await updateDoc(doc(db,config[section].collection,parentId),payload);else{payload.createdAt=serverTimestamp();parentId=(await addDoc(collection(db,config[section].collection),payload)).id;}if(files.length){const existing=await getMediaImages(pageCollection,parentId);await Promise.all(existing.map(item=>deleteDoc(doc(db,pageCollection,item.id))));for(let index=0;index<files.length;index++){button.textContent=`Image ${index+1} sur ${files.length}…`;const imageData=await compressMediaImage(files[index]);await addDoc(collection(db,pageCollection),{parentId,order:index,imageData,createdAt:serverTimestamp()});}}closeEditor();message(section==="magazines"?"Magazine enregistré.":"Album photo enregistré.");await loadAdminList();}catch(error){console.error(error);message(error.message==="image-too-large"?"Une image reste trop volumineuse. Choisissez une version plus légère.":"L’enregistrement des images a échoué.","error");}finally{button.disabled=false;button.textContent="Enregistrer";}}
