notificationButton.onclick=async()=>{const permission=await Notification.requestPermission();updateNotificationButton();if(permission==="granted"){const registration=await navigator.serviceWorker.ready;registration.showNotification("Notifications AGP activées",{body:"Vous serez averti des nouvelles activités et petites annonces.",icon:"assets/icon-tour-192.png",badge:"assets/icon-tour-192.png"});refreshMemberNews();}};
function renderMemberNewBadge(){document.querySelectorAll(".new-content-badge").forEach(badge=>badge.remove());}
async function refreshMemberNews(){if(!currentUser||!["member","admin"].includes(currentRole))return;try{const [activities,classifieds]=await Promise.all([getItems("activities"),getItems("classifieds")]),collections={activities:activities.filter(upcoming),classifieds:classifieds.filter(item=>item.status==="published")},notificationDate=(section,item)=>asDate(section==="classifieds"?(item.publishedAt||item.reviewedAt||item.createdAt):item.createdAt);for(const [section,items] of Object.entries(collections)){const seen=Number(localStorage.getItem(`agp-seen-${section}`)||0),fresh=items.filter(item=>notificationDate(section,item).getTime()>seen),newest=[...items].sort((a,b)=>notificationDate(section,b)-notificationDate(section,a))[0];renderMemberNewBadge(section,fresh.length);if(newest&&"Notification" in window&&Notification.permission==="granted"){const notificationKey=`agp-notified-${section}`,lastNotified=localStorage.getItem(notificationKey);if(lastNotified&&lastNotified!==newest.id){const registration=await navigator.serviceWorker.ready;registration.showNotification(section==="activities"?"Nouvelle activité AGP":"Nouvelle petite annonce",{body:newest.title||"Un nouveau contenu est disponible.",icon:"assets/icon-tour-192.png",badge:"assets/icon-tour-192.png",data:{url:"./"}});}localStorage.setItem(notificationKey,newest.id);}}}catch(error){console.error(error);}updateNotificationButton();}
document.addEventListener("click",event=>{const button=event.target.closest("[data-member-section]");if(!button||!["activities","classifieds"].includes(button.dataset.memberSection))return;localStorage.setItem(`agp-seen-${button.dataset.memberSection}`,Date.now());renderMemberNewBadge(button.dataset.memberSection,0);},true);
function renderClassifiedsMenuCount(count){document.querySelectorAll('.member-summary [data-member-section="classifieds"],.bottom [data-member-section="classifieds"]').forEach(button=>{let badge=button.querySelector(".total-content-badge");if(!badge){badge=document.createElement("span");badge.className="total-content-badge";button.appendChild(badge);}badge.textContent=count;badge.hidden=!count;});}
async function refreshClassifiedsMenuCount(){if(!currentUser||!["member","admin"].includes(currentRole))return;try{const items=await getItems("classifieds");renderClassifiedsMenuCount(items.filter(item=>item.status==="published").length);}catch(error){console.error(error);}}
const loadDashboardBase=loadDashboard;loadDashboard=async function(){await loadDashboardBase();await Promise.all([refreshMemberNews(),refreshClassifiedsMenuCount()]);};
setInterval(()=>{if(currentUser&&["member","admin"].includes(currentRole)){refreshMemberNews();refreshClassifiedsMenuCount();}},60000);
addEventListener("focus",()=>{if(currentUser&&["member","admin"].includes(currentRole)){refreshMemberNews();refreshClassifiedsMenuCount();if(currentRole==="admin")updateAdminBadges();}});
document.addEventListener("visibilitychange",()=>{if(document.visibilityState==="visible"&&currentUser&&["member","admin"].includes(currentRole)){refreshMemberNews();refreshClassifiedsMenuCount();if(currentRole==="admin")updateAdminBadges();}});

const adminNotificationButton=document.createElement("button");adminNotificationButton.className="member-notification-button";adminNotificationButton.textContent="♢ Alertes administratrice";adminNotificationButton.hidden=true;document.querySelector('[data-view="admin"] .head').after(adminNotificationButton);
adminNotificationButton.onclick=async()=>{const permission=await Notification.requestPermission();updateAdminNotificationButton();if(permission==="granted"){const registration=await navigator.serviceWorker.ready;registration.showNotification("Alertes administratrice activées",{body:"Vous serez avertie lorsqu’un compte attend votre validation.",icon:"assets/icon-tour-192.png",badge:"assets/icon-tour-192.png"});refreshPendingAdminNotification();}};
function updateAdminNotificationButton(){adminNotificationButton.hidden=currentRole!=="admin"||!("Notification" in window)||Notification.permission==="granted";}
async function refreshPendingAdminNotification(){if(currentRole!=="admin")return;try{const pending=await getDocs(query(collection(db,"users"),where("role","==","pending"))),ids=pending.docs.map(item=>item.id).sort().join(","),storageKey="agp-pending-users-notified",previous=localStorage.getItem(storageKey);if(previous!==null&&previous!==ids&&pending.size>0&&"Notification" in window&&Notification.permission==="granted"){const registration=await navigator.serviceWorker.ready;registration.showNotification("Nouveau compte à valider",{body:`${pending.size} demande${pending.size>1?"s":""} d’accès en attente dans AGP & Vous.`,icon:"assets/icon-tour-192.png",badge:"assets/icon-tour-192.png",data:{url:"./"}});}localStorage.setItem(storageKey,ids);}catch(error){console.error(error);}updateAdminNotificationButton();}
const updateAdminBadgesWithNotification=updateAdminBadges;updateAdminBadges=async function(){await updateAdminBadgesWithNotification();await refreshPendingAdminNotification();};

function renderSectionTotal(section,count){document.querySelectorAll(`.member-summary [data-member-section="${section}"],.member-life-grid [data-member-section="${section}"]`).forEach(button=>{let badge=button.querySelector(".section-total-badge");if(!badge){badge=document.createElement("span");badge.className="section-total-badge";button.appendChild(badge);}badge.textContent=count;badge.hidden=false;});}
async function refreshAllSectionTotals(){document.querySelectorAll("#adminMenu .admin-pending-badge,#adminMenu .section-total-badge,.new-content-badge,.total-content-badge").forEach(badge=>badge.remove());if(!currentUser||currentRole!=="member")return;try{const sections=["activities","classifieds"],results=await Promise.all(sections.map(section=>getItems(section)));sections.forEach((section,index)=>{let items=results[index];if(section==="activities")items=items.filter(item=>item.published!==false&&upcoming(item));if(section==="classifieds")items=items.filter(item=>item.status==="published");renderSectionTotal(section,items.length);});}catch(error){console.error(error);}}
refreshClassifiedsMenuCount=async function(){await refreshAllSectionTotals();};
const loadDashboardWithTotals=loadDashboard;loadDashboard=async function(){await loadDashboardWithTotals();await refreshAllSectionTotals();};
const updateAdminBadgesWithTotals=updateAdminBadges;updateAdminBadges=async function(){await updateAdminBadgesWithTotals();await refreshAllSectionTotals();};

const usefulInfoButton=document.createElement("button");
usefulInfoButton.dataset.memberSection="usefulInfo";
usefulInfoButton.innerHTML='<span>ℹ️</span><div><b>Infos utiles du Grand Pavois</b><small>Accès, sécurité et contacts</small></div>';
document.querySelector(".member-life-grid").appendChild(usefulInfoButton);
usefulInfoButton.onclick=()=>{if(!currentUser)return openLogin();route("member");renderUsefulGrandPavoisInfo();};

function renderUsefulGrandPavoisInfo(){
  currentMemberSection="usefulInfo";
  const out=$("privateResults");
  out.innerHTML=`<div class="section-title"><div><span>ESPACE PRIVÉ</span><h2>Les infos utiles du Grand Pavois</h2></div></div>
  <section class="useful-info-intro"><span>BIENVENUE</span><h3>Vous venez d’emménager au Grand Pavois ?</h3><p>L’AGP vous souhaite la bienvenue et vous propose ces informations pour faciliter votre installation et mieux comprendre le fonctionnement de l’immeuble.</p><p>L’Association du Grand Pavois est une association déclarée et assurée, créée par des copropriétaires résidents pour échanger, s’entraider et créer des moments conviviaux entre voisins. Elle propose aussi à ses adhérents une ligne téléphonique Entraide afin que personne ne reste seul face à une difficulté pouvant être résolue avec l’aide ou les conseils d’un voisin.</p></section>
  <p class="useful-info-disclaimer">Ces informations sont préparées par l’AGP à titre informatif. Elles n’ont aucun caractère officiel et ne remplacent pas les documents ou informations du syndic et de la copropriété.</p>
  <div class="useful-info-grid">
    <article><span class="useful-info-icon">🏢</span><h3>Le Grand Pavois : un IGH</h3><p>Le Grand Pavois est un Immeuble de Grande Hauteur. Il est soumis à une réglementation incendie stricte, avec la présence obligatoire d’un service de sécurité incendie SSIAP 24 h/24.</p></article>
    <article><span class="useful-info-icon">🏙️</span><h3>La résidence</h3><p>La copropriété comprend l’IGH principal de 330 appartements, le petit immeuble « Demi-Lune », des commerces au rez-de-chaussée Prado et des locaux professionnels au 25 boulevard Édouard-Herriot.</p><p>Le toit-terrasse et la piscine sont accessibles toute l’année selon les horaires été ou hiver affichés au 31e étage.</p></article>
    <article><span class="useful-info-icon">🔑</span><h3>Les accès</h3><ul><li><b>Badge noir :</b> accès à l’immeuble</li><li><b>Badge jaune :</b> accès au parking — un badge par place</li><li><b>Badge bleu :</b> accès à la piscine</li></ul><p>Les badges peuvent être reprogrammés ou refaits au bureau du syndic, au 31e étage côté Herriot. Après 21 h 30, les codes d’entrée sont désactivés.</p></article>
    <article><span class="useful-info-icon">🏠</span><h3>Les deux entrées</h3><p><b>Côté Prado :</b> 320 avenue du Prado, cinq appartements par niveau, colonnes 1 à 5.</p><p><b>Côté Herriot :</b> accès au 15 boulevard Édouard-Herriot, six appartements par niveau, colonnes 6 à 11.</p><p>Pour les déménagements et livraisons importantes, privilégiez l’entrée Herriot.</p></article>
    <article><span class="useful-info-icon">🚚</span><h3>Visiteurs et livreurs</h3><p>Les codes ouvrant les grilles côté rue sont modifiés régulièrement. Après 21 h 30, l’accès se fait uniquement avec un badge. Les visiteurs accèdent ensuite aux ascenseurs grâce à l’interphone des appartements.</p><p>Pour un déménagement ou une livraison importante, privilégiez l’entrée Herriot.</p></article>
    <article><span class="useful-info-icon">↕️</span><h3>À chaque étage</h3><ul><li>Deux ascenseurs du parking −2 au 31e étage</li><li>Un monte-charge, hors sous-sols, caves, garages et 31e étage</li><li>Un local vide-ordures avec extincteur de chaque côté</li><li>Un couloir sécurisé et deux sas donnant accès aux escaliers</li></ul><p>Au 31e étage se trouvent le Club House côté Prado et le bureau du syndic côté Herriot.</p></article>
    <article><span class="useful-info-icon">♻️</span><h3>Les déchets</h3><p>Les poubelles sont sorties chaque fin d’après-midi côté Herriot. Des conteneurs sont disponibles dans les parkings en sous-sol en journée. Les conteneurs de recyclage se trouvent boulevard Herriot, face au portail.</p></article>
    <article><span class="useful-info-icon">🚿</span><h3>Conseil pratique</h3><p>L’AGP conseille d’équiper les salles de bains de pommeaux anti-légionellose, cette bactérie étant présente dans les canalisations de l’immeuble.</p></article>
  </div>
  <section class="useful-info-contact emergency"><span>PC SÉCURITÉ — 24 H/24</span><h3>Agents SSIAP — société Buckler</h3><p>Signalez en priorité au PC sécurité toute panne importante — EDF, eau, VMC — toute fuite ou difficulté nécessitant une intervention. Les agents préviennent les risques d’incendie, surveillent les équipements, interviennent en cas d’alarme et assistent les personnes en difficulté.</p><p>Le PC remet les fiches d’information des résidents et les formulaires pour les plaques nominatives et l’interphone. Il n’est pas un service de conciergerie : il ne fournit pas de renseignements administratifs, ne réceptionne pas les colis et n’effectue aucun stockage.</p><a href="tel:+33491777334">☎ 04 91 77 73 34</a></section>
  <section class="useful-info-contact"><span>SYNDIC LAMY — 31e ÉTAGE CÔTÉ HERRIOT</span><h3>Gestionnaire : M. Laurent Ayache</h3><p>Le syndic assure la gestion administrative, juridique et financière ainsi que le suivi technique de la copropriété.</p><div class="office-hours"><b>Permanences</b><p>Lundi 9 h–12 h · Mardi 14 h–17 h · Mercredi 10 h–12 h · Jeudi et vendredi 13 h 30–16 h 30. Ces horaires peuvent changer selon les impératifs de l’immeuble.</p></div><div class="contact-links"><a href="tel:+33496121673">☎ 04 96 12 16 73</a><a href="tel:+33625770782">📱 06 25 77 07 82</a><a href="mailto:layache@lamy-immobilier.fr">✉ layache@lamy-immobilier.fr</a></div></section>
  <section class="useful-info-contact"><span>CONSEIL SYNDICAL</span><h3>Neuf copropriétaires élus en Assemblée Générale</h3><p>Le Conseil Syndical assiste et contrôle le syndic dans la gestion de l’immeuble.</p><a href="mailto:conseilsyndicalgp@googlegroups.com">✉ conseilsyndicalgp@googlegroups.com</a></section>
  <section class="floor-plan"><div><span>SE REPÉRER</span><h3>Plan d’un palier</h3><p>Appartements, ascenseurs, monte-charge, escaliers, portes de secours et locaux techniques.</p></div><a href="assets/plan-palier-grand-pavois.jpg" target="_blank" rel="noopener noreferrer"><img src="assets/plan-palier-grand-pavois.jpg" alt="Plan des paliers Prado et Herriot du Grand Pavois" loading="lazy"></a><small>Schéma créé par l’AGP à titre informatif, sans caractère officiel.</small></section>`;
  out.scrollIntoView({behavior:"smooth",block:"start"});
}
